## Common patterns

### With Tooltip

Icon buttons should typically include a tooltip to provide additional context for sighted users:

```jsx live-dev
const App = () => {
  const [count, setCount] = useState(0);

  return (
    <Stack direction="column" gap="400" alignItems="center">
      <Stack direction="row" gap="300">
        <Tooltip.Root>
          <IconButton
            aria-label="Add item"
            onPress={() => setCount(count + 1)}
          >
            <Icons.Add />
          </IconButton>
          <Tooltip.Content>Add item</Tooltip.Content>
        </Tooltip.Root>

        <Tooltip.Root>
          <IconButton
            aria-label="Remove item"
            onPress={() => setCount(Math.max(0, count - 1))}
            isDisabled={count === 0}
          >
            <Icons.Remove />
          </IconButton>
          <Tooltip.Content>Remove item</Tooltip.Content>
        </Tooltip.Root>
      </Stack>
      <Text fontSize="sm">Count: {count}</Text>
    </Stack>
  );
}
```

### Loading state

Show a loading state during asynchronous operations:

```jsx live-dev
const App = () => {
  const [isLoading, setIsLoading] = useState(false);

  const handlePress = () => {
    setIsLoading(true);
    setTimeout(() => setIsLoading(false), 2000);
  };

  return (
    <Stack direction="column" gap="400" alignItems="center">
      <IconButton
        aria-label="Save changes"
        onPress={handlePress}
        isLoading={isLoading}
      >
        <Icons.Save />
      </IconButton>
      <Text fontSize="sm">
        {isLoading ? 'Saving...' : 'Click to save'}
      </Text>
    </Stack>
  );
}
```

### Icon button group

Group related icon buttons using Stack:

```jsx live-dev
const App = () => {
  const [alignment, setAlignment] = useState('left');

  return (
    <Stack direction="column" gap="400">
      <Stack direction="row" gap="200">
        <IconButton
          aria-label="Align left"
          variant={alignment === 'left' ? 'solid' : 'ghost'}
          onPress={() => setAlignment('left')}
        >
          <Icons.FormatAlignLeft />
        </IconButton>
        <IconButton
          aria-label="Align center"
          variant={alignment === 'center' ? 'solid' : 'ghost'}
          onPress={() => setAlignment('center')}
        >
          <Icons.FormatAlignCenter />
        </IconButton>
        <IconButton
          aria-label="Align right"
          variant={alignment === 'right' ? 'solid' : 'ghost'}
          onPress={() => setAlignment('right')}
        >
          <Icons.FormatAlignRight />
        </IconButton>
      </Stack>
      <Text fontSize="sm">Alignment: {alignment}</Text>
    </Stack>
  );
}
```

## Testing your implementation

These examples demonstrate how to test your implementation when using IconButton within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the IconButton renders correctly with required props

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { IconButton, NimbusProvider } from "@commercetools/nimbus";
import { Add as AddIcon } from "@commercetools/nimbus-icons";

describe("IconButton - Basic rendering", () => {
  it("renders button with icon", () => {
    render(
      <NimbusProvider>
        <IconButton aria-label="Add item">
          <AddIcon />
        </IconButton>
      </NimbusProvider>
    );

    const button = screen.getByRole("button", { name: /add item/i });
    expect(button).toBeInTheDocument();
  });

  it("renders with required aria-label", () => {
    render(
      <NimbusProvider>
        <IconButton aria-label="Open menu">
          <AddIcon />
        </IconButton>
      </NimbusProvider>
    );

    const button = screen.getByRole("button", { name: /open menu/i });
    expect(button).toHaveAttribute("aria-label", "Open menu");
  });

  it("renders with custom data attributes", () => {
    render(
      <NimbusProvider>
        <IconButton aria-label="Test button" data-testid="custom-button">
          <AddIcon />
        </IconButton>
      </NimbusProvider>
    );

    expect(screen.getByTestId("custom-button")).toBeInTheDocument();
  });
});
```

### Interaction Tests

Test user interactions with the IconButton

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { IconButton, NimbusProvider } from "@commercetools/nimbus";
import { Add as AddIcon } from "@commercetools/nimbus-icons";

describe("IconButton - Interactions", () => {
  it("calls onPress when clicked", async () => {
    const user = userEvent.setup();
    const handlePress = vi.fn();

    render(
      <NimbusProvider>
        <IconButton aria-label="Add item" onPress={handlePress}>
          <AddIcon />
        </IconButton>
      </NimbusProvider>
    );

    const button = screen.getByRole("button", { name: /add item/i });
    await user.click(button);

    expect(handlePress).toHaveBeenCalledTimes(1);
  });

  it("does not call onPress when disabled", async () => {
    const user = userEvent.setup();
    const handlePress = vi.fn();

    render(
      <NimbusProvider>
        <IconButton aria-label="Add item" onPress={handlePress} isDisabled>
          <AddIcon />
        </IconButton>
      </NimbusProvider>
    );

    const button = screen.getByRole("button", { name: /add item/i });
    await user.click(button);

    expect(handlePress).not.toHaveBeenCalled();
  });
});
```

### Keyboard Navigation Tests

Test keyboard interactions with the IconButton

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { IconButton, NimbusProvider } from "@commercetools/nimbus";
import { Add as AddIcon } from "@commercetools/nimbus-icons";

describe("IconButton - Keyboard navigation", () => {
  it("is focusable with Tab key", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <IconButton aria-label="Add item">
          <AddIcon />
        </IconButton>
      </NimbusProvider>
    );

    const button = screen.getByRole("button", { name: /add item/i });

    await user.tab();

    expect(button).toHaveFocus();
  });

  it("can be activated with Enter key", async () => {
    const user = userEvent.setup();
    const handlePress = vi.fn();

    render(
      <NimbusProvider>
        <IconButton aria-label="Add item" onPress={handlePress}>
          <AddIcon />
        </IconButton>
      </NimbusProvider>
    );

    const button = screen.getByRole("button", { name: /add item/i });
    button.focus();

    await user.keyboard("{Enter}");

    expect(handlePress).toHaveBeenCalledTimes(1);
  });

  it("can be activated with Space key", async () => {
    const user = userEvent.setup();
    const handlePress = vi.fn();

    render(
      <NimbusProvider>
        <IconButton aria-label="Add item" onPress={handlePress}>
          <AddIcon />
        </IconButton>
      </NimbusProvider>
    );

    const button = screen.getByRole("button", { name: /add item/i });
    button.focus();

    await user.keyboard(" ");

    expect(handlePress).toHaveBeenCalledTimes(1);
  });
});
```

### State Tests

Test different states of the IconButton

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { IconButton, NimbusProvider } from "@commercetools/nimbus";
import { Add as AddIcon } from "@commercetools/nimbus-icons";

describe("IconButton - States", () => {
  it("applies disabled state", () => {
    render(
      <NimbusProvider>
        <IconButton aria-label="Add item" isDisabled>
          <AddIcon />
        </IconButton>
      </NimbusProvider>
    );

    const button = screen.getByRole("button", { name: /add item/i });
    expect(button).toBeDisabled();
  });
});
```

### Visual Variant Tests

Test different visual variants and sizes

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { IconButton, NimbusProvider } from "@commercetools/nimbus";
import { Add as AddIcon } from "@commercetools/nimbus-icons";

describe("IconButton - Visual variants", () => {
  it("renders with different size variants", () => {
    const { rerender } = render(
      <NimbusProvider>
        <IconButton aria-label="Small button" size="xs">
          <AddIcon />
        </IconButton>
      </NimbusProvider>
    );

    expect(screen.getByRole("button")).toBeInTheDocument();

    rerender(
      <NimbusProvider>
        <IconButton aria-label="Medium button" size="md">
          <AddIcon />
        </IconButton>
      </NimbusProvider>
    );

    expect(screen.getByRole("button")).toBeInTheDocument();
  });

  it("renders with different visual variants", () => {
    const { rerender } = render(
      <NimbusProvider>
        <IconButton aria-label="Solid button" variant="solid">
          <AddIcon />
        </IconButton>
      </NimbusProvider>
    );

    expect(screen.getByRole("button")).toBeInTheDocument();

    rerender(
      <NimbusProvider>
        <IconButton aria-label="Outline button" variant="outline">
          <AddIcon />
        </IconButton>
      </NimbusProvider>
    );

    expect(screen.getByRole("button")).toBeInTheDocument();
  });

  it("renders with color palettes", () => {
    render(
      <NimbusProvider>
        <IconButton aria-label="Primary action" colorPalette="primary">
          <AddIcon />
        </IconButton>
      </NimbusProvider>
    );

    expect(screen.getByRole("button")).toBeInTheDocument();
  });
});
```


